import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import Navbar from '../components/Navbar';

const API = '';

const nama = 'Hagia Sofiana';
const tentang =
  'Full Stack Developer specializing in modern web and mobile development. Proficient in PHP, Laravel, JavaScript, React, Python, Java, and MySQL, with a passion for building scalable applications, writing clean code, and continuously exploring new technologies.';

const roles = [
  'Software Engineer',
  'Full Stack Developer',
  'Frontend Developer',
  'Backend Developer',
  'React Developer',
  'Node.js Developer'
];

const techStack = [
  { name: 'React', icon: 'react' },
  { name: 'Node.js', icon: 'nodejs' },
  { name: 'Express', icon: 'express' },
  { name: 'JavaScript', icon: 'javascript' },
  { name: 'PHP', icon: 'php' },
  { name: 'Laravel', icon: 'laravel' },
  { name: 'MySQL', icon: 'mysql' },
  { name: 'Git', icon: 'git' },
  { name: 'GitHub', icon: 'github' },
  { name: 'Bootstrap', icon: 'bootstrap' },
  { name: 'Tailwind CSS', icon: 'tailwindcss' },
  { name: 'VS Code', icon: 'vscode' },
  { name: 'Figma', icon: 'figma' },
  { name: 'Postman', icon: 'postman' }
];

export default function Home() {
  const [roleIndex, setRoleIndex] = useState(0);
  const [cursorPosition, setCursorPosition] = useState({ x: 0, y: 0 });

  useEffect(() => {
    window.scrollTo(0, 0);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setRoleIndex((prev) => (prev + 1) % roles.length);
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const handleMouseMove = (e) => {
      setCursorPosition({ x: e.clientX, y: e.clientY });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  const marqueeItems = [...techStack, ...techStack, ...techStack];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700;800;900&family=Inter:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600;700&display=swap');

        :root {
          --bg-primary: #111114;
          --bg-secondary: #18181C;
          --surface: #202025;
          --accent-pink: #FF3EA5;
          --accent-secondary: #FF77C8;
          --rose-gold: #D8A7B1;
          --text-primary: #F5F5F5;
          --text-secondary: #A8A8A8;
          --border-color: rgba(255,255,255,.08);
          --glow-pink: rgba(255,62,165,.15);
        }

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
          background: var(--bg-primary);
          color: var(--text-primary);
          min-height: 100vh;
          font-family: 'Inter', sans-serif;
          overflow-x: hidden;
        }

        /* Background Layers */
        .bg-layer {
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          background: var(--bg-primary);
        }

        /* Pink Glow behind profile */
        .bg-glow {
          position: fixed;
          width: 800px;
          height: 800px;
          border-radius: 50%;
          background: radial-gradient(circle, rgba(255,62,165,0.12) 0%, transparent 70%);
          top: 50%;
          right: 0;
          transform: translateY(-50%);
          pointer-events: none;
          z-index: 0;
        }

        /* Leopard Texture - Very Subtle */
        .bg-leopard {
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          opacity: 0.03;
          background-image: 
            radial-gradient(ellipse at 20% 30%, rgba(255,62,165,0.02) 0%, transparent 4px),
            radial-gradient(ellipse at 80% 70%, rgba(255,62,165,0.015) 0%, transparent 3px),
            radial-gradient(ellipse at 40% 60%, rgba(255,62,165,0.01) 0%, transparent 2px);
          background-size: 120px 120px, 180px 180px, 200px 200px;
        }

        /* Noise Texture */
        .bg-noise {
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          opacity: 0.04;
          background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.04'/%3E%3C/svg%3E");
          mix-blend-mode: overlay;
        }

        .main-content {
          position: relative;
          z-index: 1;
          min-height: 100vh;
          display: flex;
          flex-direction: column;
        }

        /* Hero Section - Full Screen */
        .hero-section {
          flex: 1;
          min-height: 90vh;
          display: flex;
          align-items: center;
          padding: 6rem 0 4rem;
          position: relative;
        }

        /* Profile Image - Large Background Element */
        .profile-container {
          position: relative;
          width: 100%;
          height: 100%;
          display: flex;
          align-items: center;
          justify-content: flex-end;
        }

        .profile-image-wrapper {
          position: relative;
          width: 600px;
          height: 600px;
          border-radius: 50%;
          overflow: hidden;
          mask-image: radial-gradient(circle at center, black 60%, transparent 75%);
          -webkit-mask-image: radial-gradient(circle at center, black 60%, transparent 75%);
        }

        .profile-image {
          width: 100%;
          height: 100%;
          object-fit: cover;
          object-position: center;
        }

        /* Hero Content - Left Aligned */
        .hero-content {
          position: relative;
          z-index: 2;
          padding-right: 2rem;
        }

        .hero-greeting {
          font-size: 0.9rem;
          color: var(--text-secondary);
          margin-bottom: 1rem;
          font-weight: 400;
          letter-spacing: 0.5px;
        }

        .hero-name {
          font-family: 'Space Grotesk', sans-serif;
          font-size: 5rem;
          font-weight: 900;
          line-height: 1.05;
          margin-bottom: 0.5rem;
          letter-spacing: -3px;
        }

        .hero-name .highlight {
          background: linear-gradient(135deg, var(--accent-pink), var(--accent-secondary), var(--rose-gold));
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        /* Rotating Title */
        .rotating-title-container {
          height: 4rem;
          overflow: hidden;
          margin-bottom: 1.5rem;
          position: relative;
        }

        .rotating-title-track {
          display: flex;
          flex-direction: column;
          animation: slideVertical 18s ease-in-out infinite;
        }

        @keyframes slideVertical {
          0%, 14.28% { transform: translateY(0); }
          16.66%, 30.94% { transform: translateY(-4rem); }
          33.32%, 47.6% { transform: translateY(-8rem); }
          49.98%, 64.26% { transform: translateY(-12rem); }
          66.64%, 80.92% { transform: translateY(-16rem); }
          83.3%, 97.58% { transform: translateY(-20rem); }
          100% { transform: translateY(-24rem); }
        }

        .rotating-title-item {
          height: 4rem;
          display: flex;
          align-items: center;
          font-family: 'Space Grotesk', sans-serif;
          font-size: 2.5rem;
          font-weight: 700;
          color: var(--text-secondary);
        }

        .rotating-title-item .accent {
          color: var(--accent-pink);
        }

        .hero-description {
          font-size: 1.05rem;
          color: var(--text-secondary);
          max-width: 520px;
          line-height: 1.8;
          margin-bottom: 2.5rem;
          font-weight: 300;
        }

        .hero-actions {
          display: flex;
          align-items: center;
          gap: 1.5rem;
          flex-wrap: wrap;
          margin-bottom: 2.5rem;
        }

        .btn-primary {
          display: inline-flex;
          align-items: center;
          gap: 0.75rem;
          padding: 0.9rem 2.8rem;
          border-radius: 50px;
          background: var(--accent-pink);
          color: #fff;
          font-weight: 600;
          font-size: 0.95rem;
          text-decoration: none;
          transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
          border: none;
          cursor: pointer;
          position: relative;
          overflow: hidden;
          box-shadow: 0 0 40px rgba(255,62,165,0.15);
        }

        .btn-primary:hover {
          transform: translateY(-3px) scale(1.02);
          box-shadow: 0 20px 60px rgba(255,62,165,0.3);
        }

        .btn-primary .arrow {
          display: inline-block;
          transition: transform 0.3s ease;
        }

        .btn-primary:hover .arrow {
          transform: translateX(6px);
        }

        .social-links {
          display: flex;
          gap: 0.75rem;
        }

        .social-link {
          width: 44px;
          height: 44px;
          border-radius: 50%;
          background: rgba(255,255,255,.03);
          border: 1px solid var(--border-color);
          display: inline-flex;
          align-items: center;
          justify-content: center;
          color: var(--text-secondary);
          text-decoration: none;
          font-size: 1.1rem;
          transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
        }

        .social-link:hover {
          background: var(--accent-pink);
          color: #fff;
          transform: translateY(-3px);
          border-color: var(--accent-pink);
          box-shadow: 0 10px 30px rgba(255,62,165,0.2);
        }

        /* Tech Stack Marquee */
        .tech-marquee-section {
          padding: 2.5rem 0;
          border-top: 1px solid var(--border-color);
          border-bottom: 1px solid var(--border-color);
          background: var(--bg-secondary);
          position: relative;
          overflow: hidden;
        }

        .tech-marquee-track {
          display: flex;
          gap: 3rem;
          animation: marqueeScroll 25s linear infinite;
          width: max-content;
        }

        @keyframes marqueeScroll {
          0% { transform: translateX(0); }
          100% { transform: translateX(-33.33%); }
        }

        .tech-item {
          display: flex;
          align-items: center;
          gap: 0.75rem;
          padding: 0.5rem 1.5rem;
          background: var(--surface);
          border-radius: 50px;
          border: 1px solid var(--border-color);
          transition: all 0.3s ease;
          flex-shrink: 0;
          white-space: nowrap;
          cursor: default;
        }

        .tech-item:hover {
          border-color: var(--accent-pink);
          transform: translateY(-2px);
          box-shadow: 0 10px 30px rgba(255,62,165,0.05);
        }

        .tech-icon {
          width: 24px;
          height: 24px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 1.2rem;
          color: var(--text-secondary);
        }

        .tech-icon svg {
          width: 100%;
          height: 100%;
          fill: currentColor;
        }

        .tech-name {
          font-size: 0.85rem;
          font-weight: 500;
          color: var(--text-secondary);
        }

        /* View Projects Button */
        .view-projects-wrapper {
          padding: 3rem 0;
          text-align: center;
          background: var(--bg-primary);
        }

        .btn-outline {
          display: inline-flex;
          align-items: center;
          gap: 0.75rem;
          padding: 1rem 3.5rem;
          border-radius: 50px;
          background: transparent;
          border: 1px solid var(--border-color);
          color: var(--text-primary);
          font-weight: 600;
          font-size: 0.95rem;
          text-decoration: none;
          transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
          cursor: pointer;
        }

        .btn-outline:hover {
          border-color: var(--accent-pink);
          box-shadow: 0 0 40px rgba(255,62,165,0.1);
          transform: translateY(-3px);
        }

        .btn-outline .arrow {
          display: inline-block;
          transition: transform 0.3s ease;
        }

        .btn-outline:hover .arrow {
          transform: translateX(6px);
        }

        /* Footer */
        .footer {
          padding: 2rem 0;
          border-top: 1px solid var(--border-color);
          background: var(--bg-secondary);
        }

        .footer-text {
          color: var(--text-secondary);
          font-size: 0.8rem;
          text-align: center;
          letter-spacing: 0.5px;
        }

        .footer-text .heart {
          color: var(--accent-pink);
          display: inline-block;
          animation: heartPulse 1.5s ease-in-out infinite;
        }

        @keyframes heartPulse {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.2); }
        }

        /* Responsive */
        @media (max-width: 1200px) {
          .profile-image-wrapper {
            width: 500px;
            height: 500px;
          }
          .hero-name {
            font-size: 4rem;
          }
          .rotating-title-item {
            font-size: 2rem;
          }
        }

        @media (max-width: 992px) {
          .hero-section {
            padding: 4rem 0 2rem;
            min-height: auto;
          }
          .profile-image-wrapper {
            width: 400px;
            height: 400px;
            margin: 2rem auto;
          }
          .hero-content {
            padding-right: 0;
            text-align: center;
          }
          .hero-description {
            margin: 0 auto 2rem;
          }
          .hero-actions {
            justify-content: center;
          }
          .hero-name {
            font-size: 3.5rem;
          }
          .rotating-title-container {
            height: 3.2rem;
          }
          .rotating-title-item {
            height: 3.2rem;
            font-size: 1.8rem;
            justify-content: center;
          }
          @keyframes slideVertical {
            0%, 14.28% { transform: translateY(0); }
            16.66%, 30.94% { transform: translateY(-3.2rem); }
            33.32%, 47.6% { transform: translateY(-6.4rem); }
            49.98%, 64.26% { transform: translateY(-9.6rem); }
            66.64%, 80.92% { transform: translateY(-12.8rem); }
            83.3%, 97.58% { transform: translateY(-16rem); }
            100% { transform: translateY(-19.2rem); }
          }
        }

        @media (max-width: 768px) {
          .profile-image-wrapper {
            width: 320px;
            height: 320px;
          }
          .hero-name {
            font-size: 2.8rem;
            letter-spacing: -1px;
          }
          .rotating-title-container {
            height: 2.8rem;
          }
          .rotating-title-item {
            height: 2.8rem;
            font-size: 1.5rem;
          }
          @keyframes slideVertical {
            0%, 14.28% { transform: translateY(0); }
            16.66%, 30.94% { transform: translateY(-2.8rem); }
            33.32%, 47.6% { transform: translateY(-5.6rem); }
            49.98%, 64.26% { transform: translateY(-8.4rem); }
            66.64%, 80.92% { transform: translateY(-11.2rem); }
            83.3%, 97.58% { transform: translateY(-14rem); }
            100% { transform: translateY(-16.8rem); }
          }
          .hero-description {
            font-size: 0.95rem;
          }
          .btn-primary {
            padding: 0.8rem 2rem;
            font-size: 0.85rem;
          }
          .tech-item {
            padding: 0.4rem 1rem;
            font-size: 0.75rem;
          }
          .bg-glow {
            width: 400px;
            height: 400px;
          }
        }

        @media (max-width: 576px) {
          .profile-image-wrapper {
            width: 260px;
            height: 260px;
          }
          .hero-name {
            font-size: 2.2rem;
          }
          .rotating-title-container {
            height: 2.2rem;
          }
          .rotating-title-item {
            height: 2.2rem;
            font-size: 1.2rem;
          }
          @keyframes slideVertical {
            0%, 14.28% { transform: translateY(0); }
            16.66%, 30.94% { transform: translateY(-2.2rem); }
            33.32%, 47.6% { transform: translateY(-4.4rem); }
            49.98%, 64.26% { transform: translateY(-6.6rem); }
            66.64%, 80.92% { transform: translateY(-8.8rem); }
            83.3%, 97.58% { transform: translateY(-11rem); }
            100% { transform: translateY(-13.2rem); }
          }
          .hero-actions {
            flex-direction: column;
            gap: 1rem;
          }
          .social-links {
            justify-content: center;
          }
          .btn-outline {
            padding: 0.8rem 2.5rem;
            font-size: 0.85rem;
          }
        }
      `}</style>

      <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" />

      {/* Background Layers */}
      <div className="bg-layer" />
      <div className="bg-glow" />
      <div className="bg-leopard" />
      <div className="bg-noise" />

      <Navbar />

      <div className="main-content">
        {/* Hero Section */}
        <section className="hero-section">
          <div className="container-fluid">
            <div className="row align-items-center">
              <div className="col-lg-6 order-2 order-lg-1">
                <motion.div
                  initial={{ opacity: 0, y: 30 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.8, ease: [0.34, 1.56, 0.64, 1] }}
